(3033, 1, '2023-02-13 05:20:05', '2023-02-13 05:20:05', '<!-- wp:kadence/rowlayout {\"uniqueID\":\"_de04e3-97\",\"colLayout\":\"equal\",\"currentOverlayTab\":\"grad\",\"maxWidth\":1200,\"topPadding\":200,\"bottomPadding\":150,\"leftPadding\":25,\"rightPadding\":25,\"topPaddingM\":115,\"bottomPaddingM\":140,\"bgImg\":\"http://localhost/wordpress/wp-content/uploads/2023/02/lucas-kapla-wQLAGv4_OYs-unsplash-1-scaled.jpg\",\"bgImgPosition\":\"50% 50%\",\"overlay\":\"palette9\",\"overlaySecond\":\"#ffffff\",\"overlayFirstOpacity\":1,\"overlaySecondOpacity\":0,\"overlayGradLoc\":55,\"overlayGradLocSecond\":36,\"overlayGradAngle\":100,\"overlayOpacity\":100,\"bottomSep\":\"\",\"firstColumnWidth\":55,\"secondColumnWidth\":45,\"mobileBackground\":[{\"enable\":true,\"bgColor\":\"\",\"bgImg\":\"https://startertemplatecloud.com/21/wp-content/uploads/sites/46/2020/09/hero-mobile-background-min.jpg\",\"bgImgID\":420,\"bgImgSize\":\"cover\",\"bgImgPosition\":\"center center\",\"bgImgAttachment\":\"scroll\",\"bgImgRepeat\":\"no-repeat\",\"forceOverDesk\":false}],\"mobileOverlay\":[{\"enable\":true,\"currentOverlayTab\":\"normal\",\"overlay\":\"palette9\",\"overlaySecond\":\"#00B5E2\",\"overlayGradLoc\":0,\"overlayGradLocSecond\":100,\"overlayGradType\":\"linear\",\"overlayGradAngle\":180,\"overlayBgImg\":\"\",\"overlayBgImgID\":\"\",\"overlayBgImgSize\":\"cover\",\"overlayBgImgPosition\":\"center center\",\"overlayBgImgAttachment\":\"scroll\",\"overlayBgImgRepeat\":\"no-repeat\",\"overlayOpacity\":90,\"overlayBlendMod\":\"none\"}]} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_de04e3-97\" class=\"kt-row-layout-inner kt-row-has-bg kt-layout-id_de04e3-97\"><div class=\"kt-row-layout-overlay kt-row-overlay-gradient\"></div><div class=\"kt-row-column-wrap kt-has-2-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row  kt-custom-first-width-55  kt-custom-second-width-45\"><!-- wp:kadence/column {\"uniqueID\":\"_993da9-39\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_993da9-39\"><div class=\"kt-inside-inner-col\"><!-- wp:kadence/advancedheading {\"level\":1,\"uniqueID\":\"_b6729b-3c\",\"size\":3.2,\"sizeType\":\"em\",\"lineHeight\":1.2,\"lineType\":\"em\",\"mobileSize\":2.4,\"fontWeight\":\"700\",\"bottomMargin\":25,\"markSize\":[\"\",\"\",\"\"],\"markLineHeight\":[\"\",\"\",\"\"],\"markFontWeight\":\"700\",\"markColor\":\"palette1\",\"markPadding\":[0,0,0,0],\"textShadow\":[{\"enable\":false,\"color\":\"rgba(0, 0, 0, 0.2)\",\"blur\":1,\"hOffset\":1,\"vOffset\":1}]} -->\n<h1 class=\"kt-adv-heading_b6729b-3c wp-block-kadence-advancedheading\" data-kb-block=\"kb-adv-heading_b6729b-3c\">Training to enrich your <mark class=\"kt-highlight\">web design skills</mark></h1>\n<!-- /wp:kadence/advancedheading -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":20}},\"textColor\":\"theme-palette5\"} -->\n<p class=\"has-theme-palette-5-color has-text-color\" style=\"font-size:20px\">Take your design skills to the next level by mastering the basics of modern web design. With this comprehensive design course, you\'ll learn everything you need to know about web design.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:kadence/advancedbtn {\"hAlign\":\"left\",\"mhAlign\":\"center\",\"btnCount\":2,\"uniqueID\":\"_c5ab22-8d\",\"btns\":[{\"text\":\"Get Started\",\"link\":\"/course/courses/web-design-course-the-complete-package/\",\"target\":\"_self\",\"size\":20,\"paddingBT\":14,\"paddingLR\":80,\"color\":\"#ffffff\",\"background\":\"palette1\",\"border\":\"palette1\",\"backgroundOpacity\":1,\"borderOpacity\":1,\"borderRadius\":6,\"borderWidth\":0,\"colorHover\":\"#ffffff\",\"backgroundHover\":\"palette2\",\"borderHover\":\"palette2\",\"backgroundHoverOpacity\":1,\"borderHoverOpacity\":1,\"icon\":\"\",\"iconSide\":\"right\",\"iconHover\":false,\"cssClass\":\"\",\"noFollow\":false,\"gap\":15,\"responsiveSiz