yle-basic kt-btn-svg-show-always kt-btn-has-text-true kt-btn-has-svg-false\" href=\"/course/courses/web-design-course-the-complete-package/\" style=\"border-radius:6px;border-width:0px\"><span class=\"kt-btn-inner-text\">Get Started</span></a></div><div class=\"kt-btn-wrap kt-btn-wrap-1\"><a class=\"kt-button button kt-btn-1-action kt-btn-size-custom kt-btn-style-basic kt-btn-svg-show-always kt-btn-has-text-true kt-btn-has-svg-false\" href=\"#design_matters\" style=\"border-radius:6px;border-width:0px\"><span class=\"kt-btn-inner-text\">Learn More</span></a></div></div>\n<!-- /wp:kadence/advancedbtn --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":2,\"uniqueID\":\"_60c3ac-c2\"} -->\n<div class=\"wp-block-kadence-column inner-column-2 kadence-column_60c3ac-c2\"><div class=\"kt-inside-inner-col\"></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_59f128-aa\",\"columns\":1,\"colLayout\":\"equal\",\"maxWidth\":1200,\"topPadding\":122,\"bottomPadding\":0,\"leftPadding\":25,\"rightPadding\":25,\"bgColor\":\"palette8\",\"overlayFirstOpacity\":1,\"overlaySecondOpacity\":1,\"overlayOpacity\":0,\"bottomSep\":\"\",\"bgColorClass\":\"theme-palette8\"} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\" id=\"design_matters\"><div id=\"kt-layout-id_59f128-aa\" class=\"kt-row-layout-inner kt-row-has-bg kt-layout-id_59f128-aa has-theme-palette-8-background-color\"><div class=\"kt-row-column-wrap kt-has-1-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row\"><!-- wp:kadence/column {\"uniqueID\":\"_5e30e9-6e\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_5e30e9-6e\"><div class=\"kt-inside-inner-col\"><!-- wp:kadence/advancedheading {\"level\":3,\"uniqueID\":\"_00f341-a9\",\"align\":\"center\",\"color\":\"palette2\",\"size\":1.1,\"sizeType\":\"em\",\"letterSpacing\":0.5,\"typography\":\"Work Sans\",\"googleFont\":true,\"fontSubset\":\"latin\",\"fontVariant\":\"500\",\"fontWeight\":\"500\",\"markSize\":[\"\",\"\",\"\"],\"markLineHeight\":[\"\",\"\",\"\"],\"markFontWeight\":\"regular\",\"markPadding\":[0,0,0,0],\"textTransform\":\"uppercase\",\"colorClass\":\"theme-palette2\",\"textShadow\":[{\"enable\":false,\"color\":\"rgba(0, 0, 0, 0.2)\",\"blur\":1,\"hOffset\":1,\"vOffset\":1}]} -->\n<h3 class=\"kt-adv-heading_00f341-a9 wp-block-kadence-advancedheading has-theme-palette-2-color has-text-color\" data-kb-block=\"kb-adv-heading_00f341-a9\"></h3>\n<!-- /wp:kadence/advancedheading -->\n\n<!-- wp:kadence/advancedheading {\"uniqueID\":\"_7055e5-8a\",\"align\":\"center\",\"size\":1.5,\"sizeType\":\"em\",\"lineHeight\":1.2,\"lineType\":\"em\",\"fontWeight\":\"700\",\"bottomMargin\":25,\"markSize\":[\"\",\"\",\"\"],\"markLineHeight\":[\"\",\"\",\"\"],\"markFontWeight\":\"regular\",\"markColor\":\"palette1\",\"markPadding\":[0,0,0,0],\"textShadow\":[{\"enable\":false,\"color\":\"rgba(0, 0, 0, 0.2)\",\"blur\":1,\"hOffset\":1,\"vOffset\":1}]} -->\n<h2 class=\"kt-adv-heading_7055e5-8a wp-block-kadence-advancedheading\" data-kb-block=\"kb-adv-heading_7055e5-8a\">Starburst’s data lakehouse analytics engine helps you run fast, live, interactive queries on your data lake</h2>\n<!-- /wp:kadence/advancedheading -->\n\n<!-- wp:image {\"id\":3030,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/data-lake-1-1024x248.png\" alt=\"\" class=\"wp-image-3030\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_3cf94f-f9\",\"columns\":1,\"colLayout\":\"equal\",\"maxWidth\":700,\"topPadding\":0,\"bottomPadding\":0,\"leftPadding\":0,\"rightPadding\":0,\"bottomMargin\":50} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_3cf94f-f9\" class=\"kt-row-layout-inner kt-layout-id_3cf94f-f9\"><div class=\"kt-row-column-wrap kt-has-1-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row\"><!-- wp:kadence/column {\"uniqueID\":\"_9a1b11-67\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_9a1b11-67\"><div class=\"kt-inside-inner-col\"><!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Based on open source Trino, the best in class SQL-based MPP query engine for open table formats and data stored in data lakes, enabling high concurrency, scalability, and performance, while increasing productivity and lowering infrastructure costs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Data lakehouse solution brief</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"backgroundColor\":\"theme-palette9\",\"textColor\":\"theme-palette3\"} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-theme-palette-3-color has-theme-palette-9-background-color has-text-color has-background wp-element-button\">Data lake white paper</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_73b8e7-6b\",\"columns\":1,\"colLayout\":\"equal\",\"maxWidth\":1200,\"topPadding\":100,\"bottomPadding\":0,\"leftPadding\":25,\"rightPadding\":25,\"bgColor\":\"palette9\",\"bgColorClass\":\"theme-palette9\"} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_73b8e7-6b\" class=\"kt-row-layout-inner kt-row-has-bg kt-layout-id_73b8e7-6b has-theme-palette-9-background-color\"><div class=\"kt-row-column-wrap kt-has-1-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row\"><!-- wp:kadence/column {\"uniqueID\":\"_29aabb-84\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_29aabb-84\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"has-text-align-center\">A flexible, fast, and secure, data lakehouse engine.</h2>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"id\":3029,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/datalke-psd-1024x377.png\" alt=\"\" class=\"wp-image-3029\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/column {\"uniqueID\":\"_223d29-da\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_223d29-da\"><div class=\"kt-inside-inner-col\"><!-- wp:kadence/rowlayout {\"uniqueID\":\"_21da88-26\",\"colLayout\":\"equal\",\"leftPadding\":25,\"rightPadding\":25} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_21da88-26\" class=\"kt-row-layout-inner kt-layout-id_21da88-26\"><div class=\"kt-row-column-wrap kt-has-2-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row\"><!-- wp:kadence/column {\"uniqueID\":\"_bbabdc-b0\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_bbabdc-b0\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"level\":4} -->\n<h4><strong>Self-managed and customizable for complex businesses</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Every organization has unique needs and infrastructure complexities. Starburst Enterprise’s open architecture works with a robust ecosystem of data sources, clients, and security and authorization tools. Customers can tailor and enhance their deployment with custom integrations and extensions.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":2,\"uniqueID\":\"_e99cc4-53\"} -->\n<div class=\"wp-block-kadence-column inner-column-2 kadence-column_e99cc4-53\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"level\":4} -->\n<h4><strong>Fully managed for your growing business</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Starburst Galaxy is cloud native, frictionless, and fully managed and is the fastest path from big data to better decisions. Kickstart your data lakehouse strategy in minutes. Leverage the agility to run interactive and ELT workloads in one query engine, with Great Lakes connectivity unifying table formats in all the most popular data lakes.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_e6eb6d-8d\",\"columns\":1,\"colLayout\":\"equal\",\"maxWidth\":800,\"topPadding\":69,\"bottomPadding\":70,\"leftPadding\":25,\"rightPadding\":25,\"bgColor\":\"palette5\",\"bgImg\":null,\"bgImgID\":null,\"overlay\":\"#090909\",\"overlaySecond\":\"palette4\",\"overlayFirstOpacity\":1,\"overlaySecondOpacity\":1,\"overlayGradAngle\":314,\"overlayOpacity\":90,\"inheritMaxWidth\":true,\"bgColorClass\":\"theme-palette5\"} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_e6eb6d-8d\" class=\"kt-row-layout-inner kt-row-has-bg kt-layout-id_e6eb6d-8d has-theme-palette-5-background-color\"><div class=\"kt-row-layout-overlay kt-row-overlay-normal\"></div><div class=\"kt-row-column-wrap kt-has-1-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row kb-theme-content-width\"><!-- wp:kadence/column {\"uniqueID\":\"_308e2f-0f\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_308e2f-0f\"><div class=\"kt-inside-inner-col\"><!-- wp:kadence/advancedheading {\"uniqueID\":\"_1d8ff4-27\",\"align\":\"center\",\"color\":\"palette9\",\"size\":2.4,\"sizeType\":\"em\",\"lineHeight\":1.5,\"lineType\":\"em\",\"mobileSize\":1.9,\"fontWeight\":\"700\",\"bottomMargin\":0,\"padding\":[\"\",\"\",20,\"\"],\"markSize\":[\"\",\"\",\"\"],\"markLineHeight\":[\"\",\"\",\"\"],\"markFontWeight\":\"regular\",\"markPadding\":[0,0,0,0],\"colorClass\":\"theme-palette9\",\"textShadow\":[{\"enable\":false,\"color\":\"rgba(0, 0, 0, 0.2)\",\"blur\":1,\"hOffset\":1,\"vOffset\":1}]} -->\n<h2 class=\"kt-adv-heading_1d8ff4-27 wp-block-kadence-advancedheading has-theme-palette-9-color has-text-color\" data-kb-block=\"kb-adv-heading_1d8ff4-27\">Lower operational costs. Better insights.</h2>\n<!-- /wp:kadence/advancedheading -->\n\n<!-- wp:kadence/advancedbtn {\"uniqueID\":\"_fa6b07-dd\",\"btns\":[{\"text\":\"Get Started\",\"link\":\"/course/courses/web-design-course-the-complete-package/\",\"target\":\"_self\",\"size\":20,\"paddingBT\":14,\"paddingLR\":40,\"color\":\"#ffffff\",\"background\":\"palette1\",\"border\":\"palette1\",\"backgroundOpacity\":1,\"borderOpacity\":1,\"borderRadius\":6,\"borderWidth\":0,\"colorHover\":\"#ffffff\",\"backgroundHover\":\"#54d1db\",\"borderHover\":\"#54d1db\",\"backgroundHoverOpacity\":1,\"borderHoverOpacity\":1,\"icon\":\"\",\"iconSide\":\"right\",\"iconHover\":false,\"cssClass\":\"\",\"noFollow\":false,\"gap\":0,\"responsiveSize\":[\"\",\"\"],\"gradient\":[\"#999999\",1,0,100,\"linear\",180,\"center center\"],\"gradientHover\":[\"#777777\",1,0,100,\"linear\",180,\"center center\"],\"btnStyle\":\"basic\",\"btnSize\":\"custom\",\"backgroundType\":\"solid\",\"backgroundHoverType\":\"solid\",\"width\":[\"\",\"\",\"\"],\"responsivePaddingBT\":[\"\",\"\"],\"responsivePaddingLR\":[\"\",\"\"],\"boxShadow\":[false,\"#000000\",0.2,1,1,2,0,false],\"boxShadowHover\":[false,\"#000000\",0.4,2,2,3,0,false],\"sponsored\":false,\"download\":false,\"tabletGap\":\"\",\"mobileGap\":\"\"}]} -->\n<div class=\"wp-block-kadence-advancedbtn kt-btn-align-center kt-btn-tablet-align-inherit kt-btn-mobile-align-inherit kt-btns-wrap kt-btns_fa6b07-dd\"><div class=\"kt-btn-wrap kt-btn-wrap-0\"><a class=\"kt-button button kt-btn-0-action kt-btn-size-custom kt-btn-style-basic kt-btn-svg-show-always kt-btn-has-text-true kt-btn-has-svg-false\" href=\"/course/courses/web-design-course-the-complete-package/\" style=\"border-radius:6px;border-width:0px\"><span class=\"kt-btn-inner-text\">Get Started</span></a></div></div>\n<!-- /wp:kadence/advancedbtn --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_5292c0-1a\",\"colLayout\":\"equal\",\"leftPadding\":150,\"rightPadding\":25,\"firstColumnWidth\":55,\"secondColumnWidth\":45} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_5292c0-1a\" class=\"kt-row-layout-inner kt-layout-id_5292c0-1a\"><div class=\"kt-row-column-wrap kt-has-2-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row  kt-custom-first-width-55  kt-custom-second-width-45\"><!-- wp:kadence/column {\"uniqueID\":\"_959dde-5a\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_959dde-5a\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"level\":3} -->\n<h3>Bring business intelligence to the data lake</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Integrate BI tools such as Tableau, ThoughtSpot, Looker, and PowerBI directly with Starburst and accelerate dashboard and reporting queries. As a single point of access Starburst delivers simple, secure, self-service live access to data, and enables your BI platform to turn insights into action immediately. Remove dependency and unnecessary strain on BI engines for live access to object storage.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":2,\"uniqueID\":\"_72064f-9a\"} -->\n<div class=\"wp-block-kadence-column inner-column-2 kadence-column_72064f-9a\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3035,\"width\":512,\"height\":335,\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"className\":\"is-style-default image-blog\"} -->\n<figure class=\"wp-block-image size-large is-resized is-style-default image-blog\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/data-lake-engine-bi-1024x670.png\" alt=\"\" class=\"wp-image-3035\" width=\"512\" height=\"335\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_c97413-89\",\"colLayout\":\"equal\",\"leftPadding\":150,\"rightPadding\":25,\"firstColumnWidth\":45,\"secondColumnWidth\":55} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_c97413-89\" class=\"kt-row-layout-inner kt-layout-id_c97413-89\"><div class=\"kt-row-column-wrap kt-has-2-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row  kt-custom-first-width-45  kt-custom-second-width-55\"><!-- wp:kadence/column {\"uniqueID\":\"_31c729-52\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_31c729-52\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3038,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/data-lake-engine-data-products-1024x621.png\" alt=\"\" class=\"wp-image-3038\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":2,\"uniqueID\":\"_73aac2-d5\"} -->\n<div class=\"wp-block-kadence-column inner-column-2 kadence-column_73aac2-d5\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"level\":3} -->\n<h3>Leverage data products for ultimate accessibility</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Enable data producers and consumers to create, publish, discover, and managed curated datasets, shortening the path from raw data to trusted insights. This free’s domain experts to generate unique insights without the burden of centralizing data. Data products are created from joining data wherever it lives, across data lakes, disparate sources, deployments, regions, or clouds.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_727143-dd\",\"colLayout\":\"equal\",\"leftPadding\":150,\"rightPadding\":25,\"firstColumnWidth\":55,\"secondColumnWidth\":45} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_727143-dd\" class=\"kt-row-layout-inner kt-layout-id_727143-dd\"><div class=\"kt-row-column-wrap kt-has-2-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row  kt-custom-first-width-55  kt-custom-second-width-45\"><!-- wp:kadence/column {\"uniqueID\":\"_084882-f5\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_084882-f5\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"level\":3} -->\n<h3>Speed, matched with robust security and compliance</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Starburst offers centralized and fine-grained control over access to all your data- query auditing, RBAC, ABAC, data masking, encryption in-flight, and more. With native features, or Integrating with incumbent security tools and policies, we help you ensure the right access for the right people. Customers can comply with various regulatory compliance standards, safely analyzing global data across clouds and regions. </p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":2,\"uniqueID\":\"_0f35b6-f9\"} -->\n<div class=\"wp-block-kadence-column inner-column-2 kadence-column_0f35b6-f9\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3040,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/data-lake-engine-security-1024x817.png\" alt=\"\" class=\"wp-image-3040\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout -->\n\n<!-- wp:kadence/column {\"background\":\"#000000\",\"uniqueID\":\"_3c165a-c9\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_3c165a-c9\"><div class=\"kt-inside-inner-col\"><!-- wp:heading {\"textAlign\":\"center\",\"textColor\":\"theme-palette9\"} -->\n<h2 class=\"has-text-align-center has-theme-palette-9-color has-text-color\"><strong>Trusted by modern data companies</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:kadence/rowlayout {\"uniqueID\":\"_a68eb7-75\",\"columns\":4,\"colLayout\":\"equal\"} -->\n<div class=\"wp-block-kadence-rowlayout alignnone\"><div id=\"kt-layout-id_a68eb7-75\" class=\"kt-row-layout-inner kt-layout-id_a68eb7-75\"><div class=\"kt-row-column-wrap kt-has-4-columns kt-gutter-default kt-v-gutter-default kt-row-valign-top kt-row-layout-equal kt-tab-layout-inherit kt-m-colapse-left-to-right kt-mobile-layout-row\"><!-- wp:kadence/column {\"uniqueID\":\"_b74a50-95\"} -->\n<div class=\"wp-block-kadence-column inner-column-1 kadence-column_b74a50-95\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3042,\"sizeSlug\":\"medium\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/priceline-logo-white-300x105.png\" alt=\"\" class=\"wp-image-3042\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":2,\"uniqueID\":\"_870f0b-70\"} -->\n<div class=\"wp-block-kadence-column inner-column-2 kadence-column_870f0b-70\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3046,\"sizeSlug\":\"medium\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/zalando-logo-white-1-300x58.png\" alt=\"\" class=\"wp-image-3046\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":3,\"uniqueID\":\"_5fd4d8-0d\"} -->\n<div class=\"wp-block-kadence-column inner-column-3 kadence-column_5fd4d8-0d\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3047,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/doordash-logo-white-1-1024x120.png\" alt=\"\" class=\"wp-image-3047\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column -->\n\n<!-- wp:kadence/column {\"id\":4,\"uniqueID\":\"_36351e-e5\"} -->\n<div class=\"wp-block-kadence-column inner-column-4 kadence-column_36351e-e5\"><div class=\"kt-inside-inner-col\"><!-- wp:image {\"id\":3048,\"sizeSlug\":\"medium\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"http://localhost/wordpress/wp-content/uploads/2023/02/finra-white-transparent-1-300x111.png\" alt=\"\" class=\"wp-image-3048\"/></figure>\n<!-- /wp:image --></div></div>\n<!-- /wp:kadence/column --></div></div></div>\n<!-- /wp:kadence/rowlayout --></div></div>\n<!-- /wp:kadence/column -->', 'Home', '', 'inherit', 'closed', 'closed', '', '543-revision-v1', '', '', '2023-02-13 05:37:27', '2023-02-13 05:37:27', '', 543, 'http://localhost/wordpress/?p=3050', 0, 'revision', '', 0);
